mapper.select:

select


tt.train_name, tt.start_time, tt.end_time, tt.train_content, tt.train_type, tt.lecturer,
tt.train_time, tt.train_address, tt.train_company, tt.certificate, tt.lecturer_information,
tt.remarks, tt.attribute1, tt.attribute2, tt.attribute3, tt.enabled_flag, tt.id, tt.create_time,
tt.create_by, tt.update_time, tt.update_by


  from td_train tt


 where 1 = 1




        and tt.start_time >= #{criteria.trainStartTime,jdbcType=DATE}
        and tt.start_time <= #{criteria.trainEndTime,jdbcType=DATE}




        and tt.enabled_flag = #{criteria.enabled,jdbcType=BIT}

